export const 入山符二 = (bi) => {
    const u = bi.u;
    const 線 = (書, 寬 = 0.6) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    bi.硃(() => {
        // 蛇行三折（一筆）：左上入，右折而返者三
        線(p => p.M(-7.4, 2.6)
            .C(-6.6, 3.4, -4.0, 3.8, -1.0, 3.8)
            .C(1.5, 3.8, 4.0, 3.6, 5.3, 3.5)
            .C(6.6, 3.6, 7.0, 4.6, 6.2, 5.3) // 右折一
            .C(4.0, 6.0, -3.0, 5.9, -5.5, 6.1)
            .C(-6.8, 6.3, -7.0, 7.3, -6.2, 8.0) // 左折
            .C(-4.0, 8.6, 3.0, 8.4, 5.4, 8.5)
            .C(6.7, 8.6, 7.0, 9.6, 6.2, 10.3) // 右折二
            .C(4.0, 11.0, -3.0, 10.8, -5.4, 11.0)
            .C(-6.5, 11.2, -6.9, 12.0, -6.5, 12.8)); // 左折收——接下豎區
        // 三豎並列（首豎自蛇尾下垂，末梢微左撇）
        線(p => p.M(-6.5, 12.8).C(-6.6, 19.0, -6.6, 26.0, -6.7, 31.5)
            .C(-6.75, 32.6, -6.9, 33.4, -7.2, 34.0));
        線(p => p.M(-4.3, 12.6).L(-4.35, 33.8));
        線(p => p.M(-2.1, 12.6).L(-2.15, 34.0));
        // 右肩折豎：橫肩右挑，折而長垂
        線(p => p.M(0.4, 14.6)
            .C(1.8, 14.3, 3.2, 14.2, 4.1, 14.0)
            .C(4.7, 13.8, 5.1, 13.3, 5.3, 12.7));
        線(p => p.M(0.4, 14.6).L(0.35, 34.2));
        // 右筒：雙豎合圓底（一筆連書：左豎下→圓底→右豎上），頂橫楣
        線(p => p.M(3.2, 16.4).L(3.2, 31.9)
            .C(3.2, 33.2, 3.8, 33.9, 4.6, 33.9)
            .C(5.4, 33.9, 6.0, 33.2, 6.0, 31.9)
            .L(6.0, 16.4));
        線(p => p.M(3.0, 16.3).C(4.0, 16.0, 5.2, 16.0, 6.2, 16.3));
    });
};
